const Summary = ({ M, T, totalInterest, formatter, schedule, setSchedule, acceleration, setAcceleration, options, setOptions }) => {
   
    return(
       <div className='card-header border-top container p-1 my-2'>
          <div className='d-flex justify-content-between'>
            <div className='d-flex'>Monthly Payment: {formatter.format(M)}</div>
            <div className='d-flex'>Term: {`${(T/12.0).toFixed(2)} Years`}</div>
            <div className='d-flex'>Total Interest: {formatter.format(totalInterest)}</div>
           </div>

           <div className='custom-control custom-switch d-flex justify-content-between my-2'>
              <div>
               <input
                  type='checkbox'
                  className='custom-control-input'
                  id='showSchedule'
                  checked={schedule}
                  onChange={setSchedule}
                  readOnly
               />
               <label className='custom-control-label' htmlFor='showSchedule'> Show Schedule</label>
               </div>
               <div>
               <input
                  type='checkbox'
                  className='custom-control-input'
                  id='showAcceleration'
                  checked={acceleration}
                  onChange={setAcceleration}
                  readOnly
               />
               <label className='custom-control-label' htmlFor='showAcceleration'> Show Acceleration</label>
               </div>
               <div>
               <input
                  type='checkbox'
                  className='custom-control-input'
                  id='showOptions'
                  checked={options}
                  onChange={setOptions}
                  readOnly
               />
               <label className='custom-control-label' htmlFor='showOptions'> Show Options</label>
               </div>
            </div>
            
        </div>
     )
   }
   
   export default Summary;